            IsPublished = true,
            SortOrder = 2,
            AppRoutes = """["/training"]""",
            Tags = """["navigation","quiz"]""",
            ContentJson = """{"passingScore":80,"questionsPerQuiz":8,"shuffleOptions":true,"showExplanationsAfterSubmit":true,"questions":[{"id":"nav1","text":"You want to find a specific job number anywhere in the app. What's the fastest way?","options":[{"id":"a","text":"Go to Backlog and use the search filter"},{"id":"b","text":"Use search in the header, or press Ctrl+K to jump to it","isCorrect":true},{"id":"c","text":"Go to Reports and run a Job Summary report"},{"id":"d","text":"Open the Board and scroll through the columns"}],"explanation":"Search in the header looks across jobs, parts, customers, and more all at once. Press Ctrl+K to jump to it from any page."},{"id":"nav2","text":"You want to share your exact filtered view of the Backlog with a teammate. What do you do?","options":[{"id":"a","text":"Take a screenshot and send it in chat"},{"id":"b","text":"Copy the web address and send it — your filters travel with it","isCorrect":true},{"id":"c","text":"Export the backlog to a file and email it"},{"id":"d","text":"Save a report with the same filters"}],"explanation":"Your filters are captured in the web address. Copying it gives your teammate the same view, filters, sorting, and page included."},{"id":"nav3","text":"The notification bell shows a red badge with '5'. What does this mean?","options":[{"id":"a","text":"5 system errors happened in the last hour"},{"id":"b","text":"You have 5 unread notifications","isCorrect":true},{"id":"c","text":"5 jobs are overdue"},{"id":"d","text":"5 compliance forms need attention"}],"explanation":"The badge on the bell shows your unread notifications. These can be job updates, assignment changes, mentions, or system alerts."},{"id":"nav4","text":"How do you switch between light and dark?","options":[{"id":"a","text":"Admin → Settings → Theme"},{"id":"b","text":"Click the sun/moon icon in the header","isCorrect":true},{"id":"c","text":"Account → Profile → Appearance"},{"id":"d","text":"Press Ctrl+D to switch"}],"explanation":"The sun/moon icon in the header switches light and dark (it's not in your picture menu). Your choice is saved and applies across your open tabs."},{"id":"nav5","text":"You're on the Expenses page and want to get to Parts quickly. Where do you click?","options":[{"id":"a","text":"The browser back button until you reach Parts"},{"id":"b","text":"The Parts icon in the side menu","isCorrect":true},{"id":"c","text":"The trail at the top of the page to step back up"},{"id":"d","text":"Search, then type 'Parts'"}],"explanation":"The side menu is how you move around. Click the Parts icon (or its label when the menu is wide) to go straight there."},{"id":"nav6","text":"Which keyboard shortcut opens the list of keyboard shortcuts?","options":[{"id":"a","text":"Ctrl+H"},{"id":"b","text":"F1"},{"id":"c","text":"/ (forward slash)","isCorrect":true},{"id":"d","text":"Ctrl+/"}],"explanation":"Press / (forward slash) from any page to see all the keyboard shortcuts. It works no matter what page you're on."},{"id":"nav7","text":"The side menu is narrow and showing only icons. How do you see the full labels?","options":[{"id":"a","text":"Click the arrow at the top of the menu","isCorrect":true},{"id":"b","text":"Press Ctrl+B to widen the menu"},{"id":"c","text":"Go to Account → Preferences → Side menu"},{"id":"d","text":"You can't — the icons are the only option"}],"explanation":"Click the arrow at the top of the menu to widen it and show full labels. Forge remembers your choice."},{"id":"nav8","text":"You bookmarked a link that had a specific job open. What happens when you open it?","options":[{"id":"a","text":"It shows an error because those links are temporary"},{"id":"b","text":"It opens the page and reopens that job's details for you","isCorrect":true},{"id":"c","text":"It sends you to the Board filtered to that job"},{"id":"d","text":"It opens the job's printable work order"}],"explanation":"An open record is captured in the link, so the bookmark reopens the page with that